yara_rules.rule:
rule MSILHeracles_AgentTesla_MothGarden_Loader
{
    meta:
        description     = "Detects MSILHeracles loader wrapping Agent Tesla — MothGarden lure variant. Matches on French botanical lure strings, fabricated developer attribution, and structural high-entropy .NET PE characteristics."
        author          = "detection-engineering-pipeline"
        date            = "2025-06-15"
        hash            = "bc37921377b4fe391a8487b7116cb8b92b3b09b1c0e9b4f48fb99f217f43eec2"
        family          = "MSILHeracles / Agent Tesla"
        reference       = "case:at.zip / MothGarden 2025-06"
        mitre_attack    = "T1027.002, T1036, T1547.001"

    strings:
        // Fabricated developer attribution — distinctive, not present in legitimate software
        $lure_attr      = "Antigravity (Google DeepMind Team)" wide ascii

        // French botanical lure UI strings — coherent set unlikely to appear together in benign software
        $lure_ui1       = "Jardin de Mousse" wide ascii
        $lure_ui2       = "Plantez vos esp" wide ascii
        $lure_ui3       = "Jardins de mousses de Kyoto" wide ascii

        // PE version-info product/description field — novel lure label with no legitimate association
        $lure_product   = "MothGarden" wide ascii

        // Randomised persistence artifact — auto-generated Run key name observed in sandbox
        $persist_key    = "qlQjUq" wide ascii nocase

        // Anomalous geolocation format strings — incongruous with a gardening app
        $geo1           = "Lat1 = {0}, Lat2 = {1}, DLat = {2}, DLon = {3}" wide ascii
        $geo2           = "Direction = {0}, ReportAlt = {1}, Index = {2}" wide ascii

        // .NET-only import stub — necessary structural marker; combined with entropy/size filters below
        $dotnet_import  = "mscoree.dll" ascii
        $dotnet_entry   = "_CorExeMain" ascii

    condition:
        // Must be a PE file
        uint16(0) == 0x5A4D and
        uint32(uint32(0x3C)) == 0x00004550 and

        // Size bracket consistent with sample (~986 KB); allow headroom for repack variants
        filesize > 500KB and filesize < 4MB and

        // .NET structure: standard managed entry point
        $dotnet_import and $dotnet_entry and

        // Match either:
        //   (a) the fabricated attribution string alone — very high specificity
        //   (b) two or more of the botanical lure strings — high specificity in combination
        //   (c) the persistence artifact string — moderate specificity; combined with lure or geo
        (
            $lure_attr or
            $lure_product or
            2 of ($lure_ui*) or
            ($persist_key and 1 of ($lure_ui*, $geo*))
        ) and

        // At least one geolocation anomaly OR one lure string must be present to avoid
        // matching arbitrary .NET binaries that happen to share common substrings
        1 of ($lure_attr, $lure_product, $lure_ui1, $lure_ui2, $lure_ui3, $geo1, $geo2, $persist_key)
}
